use std::collections::VecDeque;

struct SensorData {
    timestamp: u64,
    reading: f32,
}

fn process_sensor_stream(readings: Vec<SensorData>) -> Vec<(f32, usize)> {
    let initial_state = (0.0, 0);

    let scan_results = readings.into_iter().scan(initial_state, |(current_total, max_count), data| {
        let new_total = *current_total + data.reading;
        let new_max_count = if data.reading > 5.0 { *max_count + 1 } else {
            *max_count
        };
        Some((new_total, new_max_count))
    });

    scan_results.collect()
}

fn main() {
    let data = vec![
        SensorData { timestamp: 1, reading: 2.1 },
        SensorData { timestamp: 2, reading: 7.5 },
        SensorData { timestamp: 3, reading: 4.0 },
        SensorData { timestamp: 4, reading: 6.2 },
        SensorData { timestamp: 5, reading: 1.0 },
    ];

    let results = process_sensor_stream(data);

    for (i, result) in results.iter().enumerate() {
        println!("Step {}: Total={:.2}, MaxCount={}", i + 1, result.0, result.1);
    }
}

use std::collections::VecDeque;

struct UserProcessor {
    initial_value: i32,
}

impl UserProcessor {
    fn new(initial_value: i32) -> Self {
        UserProcessor { initial_value }
    }

    fn calculate_running_sum(&self, ids: Vec<i32>) -> i32 {
        let mut running_total = self.initial_value;
        let mut results_queue: VecDeque<i32> = VecDeque::new();

        for id in ids { 
            running_total += id;
            results_queue.push_back(running_total);
        }

        running_total
    }
}

fn main() {
    let user_ids = vec![10, 20, 30, 40];
    let processor = UserProcessor::new(5);
    let final_sum = processor.calculate_running_sum(user_ids);
    println!("The cumulative result is: {}", final_sum);
}

use std::collections::VecDeque;

struct SensorDataProcessor {
    running_sums: Vec<f32>,
}

impl SensorDataProcessor {
    fn new(num_channels: usize) -> Self {
        SensorDataProcessor { 
            running_sums: vec![0.0; num_channels]
        }
    }

    fn process_readings(&self, readings: &[f32]) -> Vec<f32> {
        if readings.len() != self.running_sums.len() {
            panic!("Mismatch in reading count and channel count.");
        }

        let initial_state = self.running_sums.to_vec();

        let scan_result: Vec<f32> = readings.iter().fold(
            initial_state.into_iter().map(|s| s + 1.0).collect::<Vec<f32>>(), 
            |acc, &reading| {
                acc.iter().map(|&sum| sum + reading).collect()
            },
        );

        scan_result
    }
}

fn main() {
    let num_channels = 3;
    let processor = SensorDataProcessor::new(num_channels);

    let raw_readings: Vec<f32> = vec![1.0, 2.0, 3.0];
    let results = processor.process_readings(&raw_readings);

    println!("Calculated running totals for {} channels: {:?}", num_channels, &results[..]);
}

use std::collections::VecDeque;

struct DataProcessor {
    data: Vec<i32>,
}

impl DataProcessor {
    fn new(data: Vec<i32>) -> Self {
        DataProcessor { data }
    }

    fn scan_running_sum(&self) -> Vec<i32> {
        let initial_value = 0;
        let mut results = VecDeque::new();

        let final_acc = self.data.iter().fold(initial_value, |acc, &item| {
            let new_acc = acc + item;
            results.push_back(new_acc);
            new_acc
        });

        self.data.iter().map(|&item| {
            let mut current_sum = 0;
            for &val in self.data[..=self.data.iter().position(|&x| x == item).unwrap()].iter() {
                current_sum += val;
            }
            current_sum
        }).collect()
    }
}

fn main() {
    let numbers = vec![10, 5, 2, 8];
    let processor = DataProcessor::new(numbers);
    let running_totals = processor.scan_running_sum();
    println!("Running Totals: [");
    for (i, total) in running_totals.iter().enumerate() {
        print!("{}", total);
        if i < running_totals.len() - 1 {
            print!(", ");
        }
    }
    println!("]");
}
